    { name: 'mk-spec-memory', version: '1.8.0' },
    { capabilities: { tools: {} } },
  );
}

const server = createContextMcpServer();
const serverWithInstructions = server as unknown as { setInstructions?: (instructions: string) => void };
const KNOWN_TOOL_NAMES = new Set(TOOL_DEFINITIONS.map((tool) => tool.name));

/* в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
   TOOL DEFINITIONS
в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */

function registerContextServerHandlers(targetServer: Server): void {
  targetServer.setRequestHandler(ListToolsRequestSchema, async () => ({
    tools: TOOL_DEFINITIONS
  }));

/* в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
   TOOL DISPATCH
в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */

// eslint-disable-next-line @typescript-eslint/no-explicit-any
  targetServer.setRequestHandler(CallToolRequestSchema, async (request, _extra: unknown): Promise<any> => {
  const requestParams = request.params as { name: string; arguments?: Record<string, unknown> };
  const { name } = requestParams;
  const args: Record<string, unknown> = requestParams.arguments ?? {};
  const callId = resolveToolCallId(request as { id?: unknown });
  const sessionTrackingId = resolveSessionTrackingId(args, _extra);
  const callerContext = buildCallerContext(_extra);
  if (sessionTrackingId) lastKnownSessionId = sessionTrackingId;

  try {
    // SEC-003: Validate input lengths before processing (CWE-400 mitigation)
    validateInputLengths(args);
    // Validate at the server boundary before metrics, session priming, and
    // auto-surface logic can observe malformed raw tool arguments.
    const validatedArgs: Record<string, unknown> = KNOWN_TOOL_NAMES.has(name)
      ? validateToolArgs(name, args) as Record<string, unknown>
      : args;

    // Track last tool call timestamp for all tools except session_health.
    if (name !== 'session_health') {
      recordToolCall(sessionTrackingId);

      // Record metric event for context quality tracking
      recordMetricEvent({ kind: 'tool_call', toolName: name });
    }
    // Classify specific tool calls for finer-grained metrics
    if (name === 'memory_context' && validatedArgs.mode === 'resume') {
      recordMetricEvent({ kind: 'memory_recovery' });
    }
    // Code-graph MCP metrics now originate from standalone mk-code-index
    if (typeof validatedArgs.specFolder === 'string' && validatedArgs.specFolder) {
      recordMetricEvent({ kind: 'spec_folder_change', specFolder: validatedArgs.specFolder as string });
    }

    const memoryRuntimeRequired = MEMORY_RUNTIME_TOOL_NAMES.has(name);
    if (memoryRuntimeRequired) {
      await ensureMemoryRuntimeInitialized(`handler:${name}`);
    }

    const dbReinitialized = memoryRuntimeRequired
      ? await checkDatabaseUpdated()
      : false;
    if (dbReinitialized) {
      await invalidateReinitializedDbCaches();
    }

    let sessionPrimeContext: AutoSurfaceResult | null = null;
    const memoryRuntimeAvailable = memoryRuntimeRequired || isMemoryRuntimeInitialized();
    if (memoryRuntimeAvailable) {
      try {
        sessionPrimeContext = await primeSessionIfNeeded(
          name,
          validatedArgs,
          sessionTrackingId,
        );
      } catch (primeErr: unknown) {
        const msg = primeErr instanceof Error ? primeErr.message : String(primeErr);
        console.error(`[context-server] Session priming failed (non-fatal): ${msg}`);
      }
    }

    // Auto-surface memories before dispatch (after validation)
    let autoSurfacedContext: AutoSurfaceResult | null = null;
    const isCompactionLifecycleCall =
      name === 'memory_context' && validatedArgs.mode === 'resume';

    const autoSurfaceStart = Date.now();
    if (MEMORY_AWARE_TOOLS.has(name) && memoryRuntimeAvailable) {
      const contextHint: string | null = extractContextHint(validatedArgs);
      if (contextHint) {
        try {
          if (isCompactionLifecycleCall) {
            autoSurfacedContext = await autoSurfaceAtCompaction(contextHint);
          } else {
            autoSurfacedContext = await autoSurfaceMemories(contextHint);
          }
        } catch (surfaceErr: unknown) {
          const msg = surfaceErr instanceof Error ? surfaceErr.message : String(surfaceErr);
          console.error(`[context-server] Auto-surface failed (non-fatal): ${msg}`);
        }
      }
    } else if (memoryRuntimeAvailable) {
      try {
        autoSurfacedContext = await autoSurfaceAtToolDispatch(name, validatedArgs);
      } catch (surfaceErr: unknown) {
        const msg = surfaceErr instanceof Error ? surfaceErr.message : String(surfaceErr);
        console.error(`[context-server] Tool-dispatch auto-surface failed (non-fatal): ${msg}`);
      }
    }
    const autoSurfaceLatencyMs = Date.now() - autoSurfaceStart;
    if (autoSurfaceLatencyMs > 250) {
      console.warn(`[context-server] Auto-surface precheck exceeded p95 target: ${autoSurfaceLatencyMs}ms`);
    }

    // Dispatch to tool modules
    const result = await runWithCallerContext(
      callerContext,
      async () => dispatchTool(name, validatedArgs, callerContext),
    ) as ToolCallResponse | null;
    if (!result) {
      throw new Error(`Unknown tool: ${name}`);
    }

    let dispatchGraphContext: DispatchGraphContextMeta | null = null;
    if (!result.isError) {
      dispatchGraphContext = await resolveDispatchGraphContext(name, validatedArgs);
    }

    runAfterToolCallbacks(name, callId, structuredClone(result));

    // Log follow_on_tool_use when a non-search tool is called after a recent search
    // Shadow-only: no ranking side effects. Fail-safe, never throws.
    if (isMemoryRuntimeInitialized() && name !== 'memory_search' && name !== 'memory_context' && name !== 'session_health') {
      try {
        const { logFollowOnToolUse } = await import('./lib/feedback/query-flow-tracker.js');
        const { requireDb } = await import('./utils/index.js');
        const db = (() => { try { return requireDb(); } catch { return null; } })();
        const followOnSessionId = sessionTrackingId ?? lastKnownSessionId;
        if (db && followOnSessionId) {
          logFollowOnToolUse(db, followOnSessionId);
        }
      } catch { /* follow_on_tool_use logging must never break dispatch */ }
    }

    // Code-search redirect hint for memory tools
    if ((name === 'memory_search' || name === 'memory_context') && result && !result.isError && result.content?.[0]?.text) {
      const queryStr = typeof args.query === 'string' ? args.query : typeof args.input === 'string' ? args.input : '';
      const codeSearchPattern = /\b(find code|implementation of|function that|where is|how does .+ work|class that|method for)\b/i;
      if (queryStr && codeSearchPattern.test(queryStr)) {
        try {
          const envelope = JSON.parse(result.content[0].text) as Record<string, unknown>;
          if (envelope && typeof envelope === 'object' && !Array.isArray(envelope)) {
            const existingHints = Array.isArray(envelope.hints) ? envelope.hints as string[] : [];
            existingHints.push('Tip: For code search queries, use mcp__mk_code_index__code_graph_query for structural lookups and Grep for exact text or token searches.');
            envelope.hints = existingHints;
            result.content[0].text = JSON.stringify(envelope, null, 2);
          }
        } catch {
          // Response is not JSON envelope вЂ” skip hint injection
        }
      }

      if (queryStr) {
        try {
          const envelope = JSON.parse(result.content[0].text) as Record<string, unknown>;
          if (envelope && typeof envelope === 'object' && !Array.isArray(envelope)) {
            const meta = typeof envelope.meta === 'object' && envelope.meta !== null && !Array.isArray(envelope.meta)
              ? envelope.meta as Record<string, unknown>
              : {};
            const snapshot = getSessionSnapshot();
            const nudge = meta.structuralRoutingNudge
              ? null
              : maybeStructuralNudge(queryStr, {
                graphReady: snapshot.graphFreshness === 'fresh',
                activationScaffoldReady: snapshot.primed,
                surface: 'response-hints',
              });
            if (nudge) {
              injectStructuralRoutingNudge(envelope, nudge);
              result.content[0].text = JSON.stringify(envelope, null, 2);
            }
          }
        } catch {
          // Response is not JSON envelope вЂ” skip structural nudge injection
        }
      }
    }

    // Passive context enrichment pipeline вЂ” adds code graph symbols
    // near mentioned file paths and session continuity warnings.
    if (result && !result.isError && result.content?.[0]?.text) {
      try {
        const { runPassiveEnrichment } = await import('./lib/enrichment/passive-enrichment.js');
        const enrichment = await runPassiveEnrichment(result.content[0].text);
        if (!enrichment.skipped && enrichment.hints.length > 0) {
          try {
            const envelope = JSON.parse(result.content[0].text) as Record<string, unknown>;
            if (envelope && typeof envelope === 'object' && !Array.isArray(envelope)) {
              const existingHints = Array.isArray(envelope.hints) ? envelope.hints as string[] : [];
              envelope.hints = [...existingHints, ...enrichment.hints];
              result.content[0].text = JSON.stringify(envelope, null, 2);
            }
          } catch {
            // Response is not JSON envelope вЂ” skip enrichment injection
          }
        }
      } catch (enrichErr: unknown) {
        // Passive enrichment is strictly non-fatal
        const msg = enrichErr instanceof Error ? enrichErr.message : String(enrichErr);
        console.warn(`[context-server] Passive enrichment failed (non-fatal): ${msg}`);
      }
    }

    // Inject auto-surface hints before token-budget enforcement so
    // The final envelope metadata reflects the fully decorated response.
    if (autoSurfacedContext && result && !result.isError) {
      appendAutoSurfaceHints(result, autoSurfacedContext);
    }

    // Token Budget Hybrid: Inject tokenBudget into response metadata
    // Enforce per-layer token budgets with actual truncation
    if (result && result.content && result.content[0]?.text) {
      try {
        const envelope = JSON.parse(result.content[0].text) as Record<string, unknown>;
        if (envelope && typeof envelope === 'object' && !Array.isArray(envelope)) {
          const metaValue = envelope.meta;
          const meta = isRecord(metaValue)
            ? metaValue as Record<string, unknown>
            : {};
          const dataValue = envelope.data;
          const data = isRecord(dataValue)
            ? dataValue as Record<string, unknown>
            : null;
          envelope.meta = meta;
          if (sessionPrimeContext && !result.isError) {
            injectSessionPrimeHints(envelope, meta, sessionPrimeContext);
          }
          if (autoSurfacedContext && !result.isError) {
            meta.autoSurfacedContext = autoSurfacedContext;
          }
          if (dispatchGraphContext && !result.isError) {
            meta.graphContext = dispatchGraphContext;
          }
          const budget = getTokenBudget(name);
          meta.tokenBudget = budget;
          syncEnvelopeTokenCount(envelope);

          if (typeof meta.tokenCount === 'number' && meta.tokenCount > budget) {
            console.error(`[token-budget] ${name} response (${meta.tokenCount} tokens) exceeds budget (${budget})`);

            // First-call session priming rides along in meta and can dwarf a
            // small tool's own payload. Slim it BEFORE touching the tool's
            // results: the tool's answer is the caller's data, the priming
            // payload is recoverable via memory_search/memory_context.
            if (isRecord(meta.sessionPriming)) {
              const priming = meta.sessionPriming as Record<string, unknown>;
              const alreadyTrimmed = priming.trimmed === true;
              if (!alreadyTrimmed) {
                const constitutionalCount = Array.isArray(priming.constitutional)
                  ? priming.constitutional.length
                  : 0;
                meta.sessionPriming = {
                  trimmed: true,
                  constitutionalCount,
                  ...(isRecord(priming.primePackage) ? { primePackage: priming.primePackage } : {}),
                };
                syncEnvelopeTokenCount(envelope);
                if (Array.isArray(envelope.hints)) {
                  envelope.hints.push(`Session priming trimmed to fit the ${budget} token budget; full constitutional content remains retrievable via memory_search`);
                }
                meta.sessionPrimingTrimmed = true;
              }
            }

            // Attempt to truncate results array to fit within budget вЂ” only
            // when still over after the priming slim above, because the loop
            // below pops a result before it re-measures.
            const stillOverBudget = typeof meta.tokenCount === 'number' && meta.tokenCount > budget;
            const innerResults = data?.results;
            if (stillOverBudget && Array.isArray(innerResults) && innerResults.length > 1) {
              const originalCount = innerResults.length;
              // Results are typically sorted by score (highest first)
              // Remove from end (lowest-scored) until within budget
              while (innerResults.length > 1) {
                innerResults.pop();
                // Recalculate token count from the full envelope
                // (not just results) so trace metadata is included in the budget.
                syncEnvelopeTokenCount(envelope);
                if (typeof meta.tokenCount === 'number' && meta.tokenCount <= budget) break;
              }
              if (data && data.count !== undefined) {
                data.count = innerResults.length;
              }
              // Recompute constitutionalCount from the results that survived truncation
              // so consumers reading data.constitutionalCount or envelope.summary see
              // counts that agree with data.results.length.
              if (data) {
                const survivingConstitutionalCount = innerResults.filter(
                  (r: unknown) => r !== null && typeof r === 'object' && (r as Record<string, unknown>).isConstitutional === true
                ).length;
                data.constitutionalCount = survivingConstitutionalCount;
                if (typeof envelope.summary === 'string') {
                  envelope.summary = survivingConstitutionalCount > 0
                    ? `Found ${innerResults.length} memories (${survivingConstitutionalCount} constitutional)`
                    : `Found ${innerResults.length} memories`;
                }
              }
              if (Array.isArray(envelope.hints)) {
                envelope.hints.push(`Token budget enforced: truncated ${originalCount} в†’ ${innerResults.length} results to fit ${budget} token budget`);
              }
              meta.tokenBudgetTruncated = true;
              meta.originalResultCount = originalCount;
              meta.returnedResultCount = innerResults.length;
            } else if (stillOverBudget) {
              // No truncatable results array вЂ” add warning hint only
              if (Array.isArray(envelope.hints)) {
                envelope.hints.push(`Response exceeds token budget (${meta.tokenCount}/${budget})`);
              }
            }
          }
          result.content[0].text = serializeEnvelopeWithTokenCount(envelope);
        }
      } catch (_parseErr: unknown) {
        // Non-JSON response, skip token budget injection
      }
    }

    return result;
  } catch (error: unknown) {
    // Include recovery hints in all error responses
    const err = error instanceof Error ? error : new Error(String(error));
    try {
      const errorResponse = buildErrorResponse(name, err, args);
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      return wrapForMCP(errorResponse as any, true);
    } catch (wrapError: unknown) {
      const fallbackError = wrapError instanceof Error ? wrapError.message : String(wrapError);
      console.error(`[context-server] Failed to build MCP error envelope for '${name}': ${fallbackError}`);
      const fallbackCode = getDefaultErrorCodeForTool(name);
      return createMCPErrorResponse({
        tool: name,
        error: 'Request failed.',
        code: fallbackCode,
        recovery: getRecoveryHint(name, fallbackCode),
      });
    }
  }
  });
}

registerContextServerHandlers(server);

